%%%%%%%%%% Function fAlsLogReadV02.m %%%%%%%%%%% Function ALS Log file Reader, ver.2% Kei Nakamura% Created on Tuesday, May 15th 2007.% Modified on Tuescday, May 15th 2007.%% function [ttl dat] = fAlsLogReadV02(fNam)% returns the name of the columns (title) and a matrix% containing the whole data of the log file.% For ALS experimetns.% ttl: title% dat: data% path: path where you find a data file. Omit shot 0.% ver.2: direct file name for argument, not path for directoryfunction [ttl,dat] = fAlsLogReadV01(fNam)  %function headerdatT = textread(fNam);dat = [datT(2:end,1) 250*datT(2:end,6) datT(2:end,7)];ttl{1} = 'shot numbeer';ttl{2} = 'Charge [pC]';ttl{3} = 'error';
